parameters.jsCode:
const item = $input.first().json;
const temp = item.main?.temp ?? null;
const feelsLike = item.main?.feels_like ?? null;
const humidity = item.main?.humidity ?? null;
const wind = item.wind?.speed ?? 0;
const gust = item.wind?.gust ?? 0;
const condId = item.weather?.[0]?.id ?? null;
const condition = item.weather?.[0]?.main ?? 'Unknown';
const desc = item.weather?.[0]?.description ?? '';
const city = item.name ?? 'Gdansk';
const reasons = [];
if (temp !== null && temp <= -5) reasons.push(`Freezing ${temp}\u00B0C`);
if (temp !== null && temp >= 30) reasons.push(`Heat ${temp}\u00B0C`);
if (wind >= 15) reasons.push(`High wind ${wind} m/s`);
if (gust >= 20) reasons.push(`Strong gusts ${gust} m/s`);
if (condId !== null && condId >= 200 && condId < 300) reasons.push('Thunderstorm');
if (condId !== null && condId >= 502 && condId < 600) reasons.push('Heavy rain');
if (condId !== null && condId >= 600 && condId < 700) reasons.push('Snow');
const isCritical = reasons.length > 0;
return [{ json: { timestamp: new Date().toISOString(), city, temp, feelsLike, humidity, wind, gust, condition, description: desc, isCritical, reason: isCritical ? reasons.join('; ') : 'Nominal' } }];

